using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK creates an instance per request,
/// resolving HttpClient and ILogger from the DI container automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (default 10)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users with limit {Limit}", limit);
        var json = await httpClient.GetStringAsync($"/users?_limit={limit}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {Id}", id);
        var response = await httpClient.GetAsync($"/users/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get all posts written by a specific user.")]
    public async Task<string> GetUserPosts(
        [Description("The user ID to fetch posts for")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var json = await httpClient.GetStringAsync($"/users/{userId}/posts", cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("Search posts by title keyword.")]
    public async Task<string> SearchPosts(
        [Description("Keyword to search for in post titles")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Query}'", query);
        var json = await httpClient.GetStringAsync($"/posts?title_like={Uri.EscapeDataString(query)}", cancellationToken);
        return json;
    }
}

