         [Description("The user ID to fetch posts for")] int userId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching posts for user {UserId}", userId);
         var json = await httpClient.GetStringAsync($"/users/{userId}/posts", cancellationToken);
         return json;
     }

     [McpServerTool(ReadOnly = true), Description("Search posts by title keyword.")]
     public async Task<string> SearchPosts(
         [Description("Keyword to search for in post titles")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Searching posts for '{Query}'", query);
         var json = await httpClient.GetStringAsync($"/posts?title_like={Uri.EscapeDataString(query)}", cancellationToken);
         return json;
     }
 }

